import asyncio
import json
import math
import time
import uuid
from dataclasses import dataclass, field
from typing import Dict, Any, Optional, Tuple, List

import websockets
from websockets.server import WebSocketServerProtocol

TICK_RATE = 20.0
SNAPSHOT_RATE = 20.0
PING_RATE = 1.0
CLIENT_TIMEOUT = 15.0

MAX_NAME_LEN = 24
MAX_CHAT_LEN = 200

WORLD_BOUNDS = (-5000.0, -5000.0, 5000.0, 5000.0)  # xmin, ymin, xmax, ymax

MAX_SPEED = 12.0
MAX_TURN_RATE = 720.0  # deg/s
MAX_PITCH_RATE = 360.0  # deg/s

MAX_HEALTH = 100
RESPAWN_ENABLED = False

def now_ms() -> int:
    return int(time.time() * 1000)

def clamp(v: float, lo: float, hi: float) -> float:
    return lo if v < lo else hi if v > hi else v

def wrap_angle_deg(a: float) -> float:
    a = (a + 180.0) % 360.0 - 180.0
    return a

def dist2(ax: float, ay: float, bx: float, by: float) -> float:
    dx = ax - bx
    dy = ay - by
    return dx * dx + dy * dy

@dataclass
class PlayerState:
    id: str
    name: str
    team: int = 0
    x: float = 0.0
    y: float = 0.0
    z: float = 0.0
    yaw: float = 0.0
    pitch: float = 0.0
    vx: float = 0.0
    vy: float = 0.0
    vz: float = 0.0
    health: int = MAX_HEALTH
    alive: bool = True
    weapon: str = "rifle"
    ammo: int = 30
    last_input_seq: int = 0
    last_heard_ms: int = field(default_factory=now_ms)
    last_shot_ms: int = 0
    score: int = 0

    def to_public_dict(self) -> Dict[str, Any]:
        return {
            "id": self.id,
            "name": self.name,
            "team": self.team,
            "pos": [self.x, self.y, self.z],
            "rot": [self.yaw, self.pitch],
            "vel": [self.vx, self.vy, self.vz],
            "health": self.health,
            "alive": self.alive,
            "weapon": self.weapon,
            "ammo": self.ammo,
            "score": self.score,
        }

@dataclass
class ClientConn:
    ws: WebSocketServerProtocol
    player_id: str
    addr: str
    last_pong_ms: int = field(default_factory=now_ms)
    last_sent_snapshot_ms: int = 0
    send_queue: asyncio.Queue = field(default_factory=asyncio.Queue)
    closed: bool = False

class GameServer:
    def __init__(self, host: str = "0.0.0.0", port: int = 8765):
        self.host = host
        self.port = port

        self.clients: Dict[str, ClientConn] = {}
        self.players: Dict[str, PlayerState] = {}

        self._lock = asyncio.Lock()
        self._server = None

        self._tick_task: Optional[asyncio.Task] = None
        self._snapshot_task: Optional[asyncio.Task] = None
        self._ping_task: Optional[asyncio.Task] = None

        self._last_tick = time.perf_counter()
        self._tick_seq = 0

    async def start(self):
        self._server = await websockets.serve(self._handle_ws, self.host, self.port, ping_interval=None, max_size=2**20)
        self._tick_task = asyncio.create_task(self._tick_loop())
        self._snapshot_task = asyncio.create_task(self._snapshot_loop())
        self._ping_task = asyncio.create_task(self._ping_loop())
        await self._server.wait_closed()

    async def stop(self):
        if self._server:
            self._server.close()
        for c in list(self.clients.values()):
            await self._disconnect(c.player_id, reason="server_stop")
        for t in [self._tick_task, self._snapshot_task, self._ping_task]:
            if t:
                t.cancel()

    async def _handle_ws(self, ws: WebSocketServerProtocol):
        addr = f"{ws.remote_address[0]}:{ws.remote_address[1]}" if ws.remote_address else "unknown"
        player_id = str(uuid.uuid4())
        name = f"Player_{player_id[:8]}"

        client = ClientConn(ws=ws, player_id=player_id, addr=addr)
        player = PlayerState(id=player_id, name=name)

        async with self._lock:
            self.clients[player_id] = client
            self.players[player_id] = player

        sender_task = asyncio.create_task(self._sender_loop(client))
        try:
            await self._send(client, {
                "type": "welcome",
                "serverTimeMs": now_ms(),
                "playerId": player_id,
                "tickRate": TICK_RATE,
                "snapshotRate": SNAPSHOT_RATE,
                "worldBounds": WORLD_BOUNDS,
            })

            await self._broadcast({
                "type": "player_join",
                "serverTimeMs": now_ms(),
                "player": player.to_public_dict(),
            }, exclude=player_id)

            async for raw in ws:
                try:
                    msg = json.loads(raw)
                except Exception:
                    continue
                await self._handle_message(client, msg)
        except websockets.ConnectionClosed:
            pass
        finally:
            await self._disconnect(player_id, reason="connection_closed")
            sender_task.cancel()

    async def _sender_loop(self, client: ClientConn):
        try:
            while True:
                msg = await client.send_queue.get()
                if client.closed:
                    return
                try:
                    await client.ws.send(msg)
                except Exception:
                    return
        except asyncio.CancelledError:
            return

    async def _send(self, client: ClientConn, payload: Dict[str, Any]):
        if client.closed:
            return
        try:
            await client.send_queue.put(json.dumps(payload, separators=(",", ":"), ensure_ascii=False))
        except Exception:
            pass

    async def _broadcast(self, payload: Dict[str, Any], exclude: Optional[str] = None):
        msg = json.dumps(payload, separators=(",", ":"), ensure_ascii=False)
        for pid, c in list(self.clients.items()):
            if exclude is not None and pid == exclude:
                continue
            if c.closed:
                continue
            try:
                await c.send_queue.put(msg)
            except Exception:
                pass

    async def _disconnect(self, player_id: str, reason: str = "unknown"):
        async with self._lock:
            client = self.clients.pop(player_id, None)
            player = self.players.pop(player_id, None)

        if client and not client.closed:
            client.closed = True
            try:
                await client.ws.close()
            except Exception:
                pass

        if player:
            await self._broadcast({
                "type": "player_leave",
                "serverTimeMs": now_ms(),
                "playerId": player_id,
                "reason": reason,
            }, exclude=None)

    async def _handle_message(self, client: ClientConn, msg: Dict[str, Any]):
        t = msg.get("type")
        pid = client.player_id

        p = self.players.get(pid)
        if not p:
            return

        p.last_heard_ms = now_ms()

        if t == "hello":
            name = str(msg.get("name", p.name))[:MAX_NAME_LEN]
            team = int(msg.get("team", p.team))
            p.name = name
            p.team = team
            await self._send(client, {
                "type": "hello_ack",
                "serverTimeMs": now_ms(),
                "player": p.to_public_dict(),
            })
            await self._broadcast({
                "type": "player_update",
                "serverTimeMs": now_ms(),
                "player": p.to_public_dict(),
            }, exclude=pid)

        elif t == "input":
            if not p.alive:
                return
            seq = int(msg.get("seq", 0))
            if seq <= p.last_input_seq:
                return
            p.last_input_seq = seq

            move = msg.get("move", [0.0, 0.0, 0.0])
            try:
                mx, my, mz = float(move[0]), float(move[1]), float(move[2])
            except Exception:
                mx, my, mz = 0.0, 0.0, 0.0

            yaw = float(msg.get("yaw", p.yaw))
            pitch = float(msg.get("pitch", p.pitch))

            mx = clamp(mx, -1.0, 1.0)
            my = clamp(my, -1.0, 1.0)
            mz = clamp(mz, -1.0, 1.0)

            p.yaw = wrap_angle_deg(yaw)
            p.pitch = clamp(pitch, -89.0, 89.0)

            mag = math.sqrt(mx * mx + my * my + mz * mz)
            if mag > 1e-6:
                mx, my, mz = mx / mag, my / mag, mz / mag

            p.vx = mx * MAX_SPEED
            p.vy = my * MAX_SPEED
            p.vz = mz * MAX_SPEED

        elif t == "shoot":
            if not p.alive:
                return
            ts = now_ms()
            if ts - p.last_shot_ms < 80:
                return
            if p.ammo <= 0:
                return
            p.last_shot_ms = ts
            p.ammo -= 1

            target_id = msg.get("targetId")
            if isinstance(target_id, str) and target_id in self.players:
                tgt = self.players[target_id]
                if tgt.alive and tgt.id != p.id:
                    d2 = dist2(p.x, p.y, tgt.x, tgt.y)
                    if d2 <= (250.0 * 250.0):
                        tgt.health = max(0, tgt.health - 25)
                        if tgt.health == 0:
                            tgt.alive = False
                            p.score += 1

            await self._broadcast({
                "type": "event_shot",
                "serverTimeMs": ts,
                "shooterId": p.id,
                "weapon": p.weapon,
                "ammo": p.ammo,
            }, exclude=None)

        elif t == "reload":
            if not p.alive:
                return
            p.ammo = 30

        elif t == "chat":
            text = str(msg.get("text", ""))[:MAX_CHAT_LEN]
            if not text:
                return
            await self._broadcast({
                "type": "chat",
                "serverTimeMs": now_ms(),
                "from": {"id": p.id, "name": p.name},
                "text": text,
            }, exclude=None)

        elif t == "pong":
            client.last_pong_ms = now_ms()

        elif t == "request_full_state":
            await self._send(client, self._build_full_state_payload())

    def _build_full_state_payload(self) -> Dict[str, Any]:
        return {
            "type": "full_state",
            "serverTimeMs": now_ms(),
            "tickSeq": self._tick_seq,
            "worldBounds": WORLD_BOUNDS,
            "players": [pl.to_public_dict() for pl in self.players.values()],
        }

    async def _tick_loop(self):
        dt_target = 1.0 / TICK_RATE
        self._last_tick = time.perf_counter()
        try:
            while True:
                t0 = time.perf_counter()
                dt = t0 - self._last_tick
                if dt < dt_target:
                    await asyncio.sleep(dt_target - dt)
                    continue
                self._last_tick = t0
                self._tick_seq += 1
                await self._step(dt)
        except asyncio.CancelledError:
            return

    async def _step(self, dt: float):
        xmin, ymin, xmax, ymax = WORLD_BOUNDS
        ts = now_ms()

        to_disconnect: List[str] = []
        for pid, p in list(self.players.items()):
            if ts - p.last_heard_ms > int(CLIENT_TIMEOUT * 1000):
                to_disconnect.append(pid)
                continue

            if not p.alive:
                if RESPAWN_ENABLED:
                    pass
                continue

            p.x += p.vx * dt
            p.y += p.vy * dt
            p.z += p.vz * dt

            p.x = clamp(p.x, xmin, xmax)
            p.y = clamp(p.y, ymin, ymax)
            p.z = clamp(p.z, -200.0, 200.0)

        for pid in to_disconnect:
            c = self.clients.get(pid)
            if c:
                await self._disconnect(pid, reason="timeout")

    async def _snapshot_loop(self):
        dt_target = 1.0 / SNAPSHOT_RATE
        try:
            while True:
                await asyncio.sleep(dt_target)
                payload = self._build_snapshot_payload()
                await self._broadcast(payload, exclude=None)
        except asyncio.CancelledError:
            return

    def _build_snapshot_payload(self) -> Dict[str, Any]:
        return {
            "type": "snapshot",
            "serverTimeMs": now_ms(),
            "tickSeq": self._tick_seq,
            "players": [p.to_public_dict() for p in self.players.values()],
        }

    async def _ping_loop(self):
        try:
            while True:
                await asyncio.sleep(PING_RATE)
                ts = now_ms()
                for pid, c in list(self.clients.items()):
                    if c.closed:
                        continue
                    if ts - c.last_pong_ms > int(CLIENT_TIMEOUT * 1000):
                        await self._disconnect(pid, reason="ping_timeout")
                        continue
                    await self._send(c, {"type": "ping", "serverTimeMs": ts})
        except asyncio.CancelledError:
            return

async def main():
    import argparse
    parser = argparse.ArgumentParser()
    parser.add_argument("--host", default="0.0.0.0")
    parser.add_argument("--port", type=int, default=8765)
    args = parser.parse_args()

    gs = GameServer(args.host, args.port)
    await gs.start()

